export interface CheckDiagnostic {
    readonly rule: "typecheck" | "typed-client" | "untyped-client" | "server-only-import" | "response-route" | "undeclared-dependency" | "server-manifest-drift";
    /** `error` fails the gate (a real contract break); `warning` is advisory — surfaced to the agent but
     * does NOT fail `nifra check`, for patterns that are sometimes intentional (a route returning a raw
     * `Response`, which silently drops the typed client to `data: never` but is valid for files/redirects). */
    readonly severity: "error" | "warning";
    readonly file?: string;
    readonly line?: number;
    readonly message: string;
    /** The canonical, rule-level fix — clean of the per-occurrence snippet, so an agent can apply it
     * directly. Set for the lint rules (they have one correct fix); omitted for `typecheck` (the fix is
     * specific to each type error). */
    readonly fix?: string;
    /** A richer, agent-oriented fix hint. Diffs are only emitted when the edit is mechanical and local;
     * ambiguous cases give concrete steps instead of pretending the checker can safely rewrite code. */
    readonly suggestion?: CheckSuggestion;
    /**
     * The import chain that pulls server-only code into the browser bundle, as display labels
     * `[routeFile, …as-written specifiers…, sink]`. Set only on `server-only-import`.
     *
     * #4.4: this is now the FULL **transitive** chain — a bounded import-resolution walk (`Bun.resolveSync`
     * from each file's dir, BFS the local module graph) follows `route → ../data → ../db → node:crypto`,
     * matching the build leak-guard's depth (`detectNodeBuiltinsInClient` in `@nifrajs/web/build`). A
     * length-2 chain (`[routeFile, specifier]`) means the route imports the sink directly. When a hop can't
     * be resolved precisely (a bare pkg, a tsconfig path alias), the walk degrades to the honest direct
     * edge rather than fabricating a deeper path — never a lie.
     */
    readonly chain?: readonly string[];
}

export interface CheckResult {
    readonly ok: boolean;
    readonly typecheck: "pass" | "fail" | "skipped";
    readonly diagnostics: readonly CheckDiagnostic[];
    /** Set only when the caller passed `maxDiagnostics` and there were more — `diagnostics` then holds the
     * first `shown` of `total`. It caps the serialized size so the `nifra_check` MCP tool can't emit a
     * message large enough to break the stdio transport; fix the shown diagnostics and re-run for the rest. */
    readonly truncated?: {
        readonly shown: number;
        readonly total: number;
    };
}

export interface CheckSuggestion {
    readonly kind: "edit" | "command" | "manual";
    readonly title: string;
    readonly diff?: string;
    /** argv array, not a shell string, so MCP clients can run it without quoting hazards. */
    readonly command?: readonly string[];
    readonly steps?: readonly string[];
}

export interface ChunkSize {
    /** The emitted file's basename (e.g. `index-abc123.js`). */
    readonly name: string;
    /** Raw byte length of the file. */
    readonly bytes: number;
    /** Gzipped byte length (what the client actually downloads, modulo brotli). */
    readonly gzip: number;
}

export interface ClientOptions {
    /** Headers sent on every request (a per-call `headers` option is merged on top). */
    readonly headers?: Record<string, string>;
    /** Override the `fetch` implementation (tests, an in-process bridge, a custom agent, etc.). */
    readonly fetch?: FetchFn;
}

export interface ClientRouter {
    /** Current state; stable reference between transitions (so `useSyncExternalStore` can bail). */
    snapshot: () => RouterState;
    /** Subscribe to transitions; returns an unsubscribe fn. */
    subscribe: (listener: () => void) => () => void;
    /** Navigate to a path: match → fetch loader data → publish. No-op for an unmatched path. */
    navigate: (path: string) => Promise<void>;
    /**
     * Submit an action (POST `body` to `action` in data mode): a redirect becomes a client
     * navigation; otherwise the data return is published as `actionData` and the active route's
     * loader is revalidated so the mutation is reflected. Pass `{ revalidate: false }` to SKIP that
     * revalidation — keep the current `data` and just publish the action's `actionData` (useful when
     * the action already returned everything that changed, saving the extra round-trip). A redirect
     * always loads its target regardless. Rejects on failure (caller falls back).
     */
    submit: (action: string, body: NonNullable<RequestInit["body"]>, opts?: SubmitOptions) => Promise<void>;
    /**
     * Mark cached route data stale and refresh the active view. With `paths`, target exactly those
     * (e.g. the routes a mutation changed); without, invalidate the whole cache. The active route
     * refreshes immediately — refetched + republished — whenever it's in scope (an explicit list that
     * includes it, or an invalidate-all); other stale entries refetch lazily when next read (a
     * fetcher, or the next navigation/access). Rejects if the active refetch fails (like `navigate`).
     * The keyed substrate for targeted revalidation (the `X-Nifra-Revalidate` header) and fetchers.
     */
    invalidate: (paths?: readonly string[]) => Promise<void>;
    /**
     * Warm a path's chunk + loader data into a bounded one-shot cache without publishing state —
     * a later `navigate` to it transitions with no network round-trip. Best-effort: failures and
     * unmatched paths are no-ops. Wired to link hover/focus by `installHistory`.
     */
    prefetch: (path: string) => Promise<void>;
    /**
     * Get (lazily creating) the stable {@link Fetcher} for `key` — an independent, concurrent
     * load/submit state machine for row-level mutations or side-channel loads that must not disturb
     * the active view. The same `key` always returns the same fetcher (so a binding can subscribe to a
     * stable store). Keys are app-chosen and typically stable (e.g. a row id).
     */
    fetcher: (key: string) => Fetcher;
    /** All live fetchers — for a global busy view (e.g. a `useFetchers` binding). */
    fetchers: () => readonly Fetcher[];
    /** Subscribe to any-fetcher-changed (a transition on any fetcher, or a new one created) — backs a
     * `useFetchers` binding; returns an unsubscribe fn. */
    subscribeFetchers: (listener: () => void) => () => void;
    /** Match a path against the manifest patterns (exposed for history/link wiring). */
    match: (path: string) => RouteMatch | null;
}

